const express = require('express')
const pool = require('../db/pool')
const result = require('../utils/result')
const router = express.Router()

router.get('/', async (req, res) => {
    const sql = 'SELECT * FROM user'
    try {
        const data = await pool.query(sql)
        // const users = result[0]
        const [users] = data
        // console.log(users)
        // res.send(users)
        res.send(result.createResult(users))
    } catch (error) {
        console.log(error)
        // res.send('error')
        //res.send(error)
        res.send(result.createResult(null, error))
    }
})

router.post('/', async (req, res) => {
    const { name, email, password, mobile, city } = req.body
    const sql = 'INSERT INTO users (name,email,password,mobile,city) VALUES(?,?,?,?,?)'
    try {
        const data = await pool.query(sql, [name, email, password, mobile, city])
        const [sqlMessage] = data
        res.send(result.createResult(sqlMessage))
    }
    catch (error) {
        res.send(result.createResult(null, error))
    }
})

router.put('/', async (req, res) => {
    const { mobile, city, uid } = req.body
    try {
        const sql = 'UPDATE users SET mobile = ? , city = ? WHERE uid = ?'
        const data = await pool.query(sql, [mobile, city, uid])
        res.send(result.createResult(data[0]))
    } catch (error) {
        res.send(result.createResult(null, error))
    }
})

router.delete('/:uid', async (req, res) => {
    const uid = req.params.uid
    const sql = 'DELETE FROM users WHERE uid = ?'
    try {
        const data = await pool.query(sql, [uid])
        res.send(result.createResult(data[0]))
    } catch (error) {
        res.send(result.createResult(null, error))
    }
})

module.exports = router

