const express = require('express')
const bcrypt = require('bcrypt') // to hash the password

// user defined modules
const pool = require('../db/pool') // provides the db connection
const result = require('../utils/result') // to create a result in standard format
const config = require('../utils/config') // to get all constants

const router = express.Router()

router.post('/signup', async (req, res) => {
    const { name, email, password, mobile, city } = req.body
    const sql = 'INSERT INTO users(name,email,password,mobile,city) VALUES(?,?,?,?,?)'
    try {
        const hashPassword = await bcrypt.hash(password, config.SALT_ROUNDS)
        const data = await pool.query(sql, [name, email, hashPassword, mobile, city])
        res.send(result.createResult(null, data[0]))
    }
    catch (error) {
        res.send(result.createResult(error))
    }
})

router.post('/signin', async (req, res) => {
    const { email, password } = req.body
    const sql = 'SELECT * FROM users WHERE email = ?'
    try {
        const data = await pool.query(sql, [email])
        const user = data[0][0]
        if (user) {
            const hashedPassword = user.password
            const status = await bcrypt.compare(password, hashedPassword)
            if (status) {
                const res_user = {
                    uid: user.uid,
                    mobile: user.mobile
                }
                res.send(result.createResult(null, res_user))
            } else
                res.send(result.createResult('Invalid password'))
        } else
            res.send(result.createResult('Invalid email'))
    } catch (error) {
        res.send(result.createResult(error))
    }
})

module.exports = router

